<template>
  <div class="login">
    <img alt="Vue logo" src="../assets/logo.png" />
    <!-- <LoginPage msg="Login Page" /> -->
    <h3>ลงชื่อเข้าใช้</h3>
    <input type="text" v-model="email" placeholder="ชื่อผู้ใช้งาน หรือ Email"><br>
    <input type="password" v-model="password" placeholder="รหัสผ่าน"><br>
    <button @click="logIn">ตกลง</button>
    <p>สามารถสมัครสมาชิกได้<router-link to="/sign-up">ที่นี่</router-link></p>
  </div>
</template>

<script>
import firebase from "firebase";

export default {
  name: "login",
  // components: {
  //   LoginPage
  // }
  data () {
    return {
      email: "",
      password: ""
    };
  },
  methods: {
    logIn: function () {
      firebase.auth().signInWithEmailAndPassword(this.email, this.password).then(
        (user) => {
          alert("ลงชื่อเข้าใช้สำเร็จ !!");
          this.$router.replace("/home");
        },
        (err) => {
          alert("Oops !!" + err.message);
        }
      );
    }
  }
};
</script>

