<template>
  <div class="sign-up">
    <img alt="Vue logo" src="../assets/logo.png" />
    <h3>สมัครสมาชิก</h3>
    <input type="text" v-model="email" placeholder="ชื่อผู้ใช้งาน หรือ Email"><br>
    <input type="password" v-model="password" placeholder="รหัสผ่าน"><br>
    <button @click="signUp">ตกลง</button>
    <p>กลับหน้า<router-link to="/login">ลงชื่อเข้าใช้</router-link></p>
  </div>
</template>

<script>
import firebase from "firebase";

export default {
  name: "signUp",
  // components: {
  //   LoginPage
  // }
  data () {
    return {
      email: '',
      password: ''
    };
  },
  methods: {
    signUp: function () {
      firebase.auth().createUserWithEmailAndPassword(this.email, this.password).then(
        (user) => {
          alert(user + 'สมัครสมาชิกสำเร็จ !!');
          this.$router.replace('/home');
        },
        (err) => {
          alert('Oops !!' + err.message);
        }
      );
    }
  }
};
</script>

